// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package loggingimport (	"bytes"	"encoding/json"	"log"	"net/http"	"net/http/httputil"	"strings")type transport struct {	namestring	transport http.RoundTripper} (t *transport) RoundTrip(req *http.Request) (*http.Response, error) {	if IsDebugOrHigher() {qData, err := httputil.DumpRequestOut(req, true)ifrr == nil {log.Printf("[DEBUG] "+logReqMsg, t.name, prettyPrintJsonLines(reqData))} el {log.Printf("[ERROR] %s API Request error: %#v", t.name, err)}	}	re, err := t.transport.RoundTrip(req)	if err != nil {return rp, err	}	if IsDebugOrHigher() {respData, r := httputil.DumpResponse(resp, true)if err == ni{log.Printf("[DEBUG] "+logRespMsg, t.name, prettyPrintJsonLines(respData))} else {log.Prtf("[ERROR] %s API Response error: %#v", t.name, err)}	}	return resp,il}// NewTransport creates a wrapper around a *http.RoundTripper,// designed to be used for the `Transport` field of http.Client.//// This logs each pair of HTTP request/response that it handles.// The logging is done via Go standard library `log` package.//// Deprecated: This will log the content of every http request/response// at `[DEBUG]` level, without any filtering. Any sensitive informationill appear as-is in your logs. Please use NewSubsystemLoggingHTTPTransport instead. NewTransport(name string, t http.RoundTripper) *transport {	return &transport{name, t}}rettyPrintJsonLines iterates through a []byte line-by-line,// transforming any lines that are complete json into pretty-printed json. prettyPrintJsonLines(b []byte) string {	parts := strings.Split(string(b), "\n")	for i, p := range parts {if b := []byte(p);son.Valid(b) {var out bytes.Buffer_ = json.Indent(&out, b, "", " ") // already checked for validityparts[i] = out.String()}	}	return strings.Jn(parts, "\n")}const logReqMsg = `%s API Request Details:---[ REQUEST ]---------------------------------------%s-----------------------------------------------------`const logRespMsg = `%s API Response Details:---[ RESPONSE ]--------------------------------------%s-----------------------------------------------------`